#include <stdio.h>
int main() {
    int T, n, k;
    scanf("%d", &T);
    while (T--) {
        scanf("%d %d", &n, &k);
        int arr[n];
        for (int i = 0; i < n; i++) {
            scanf("%d", &arr[i]);
        }
        for (int i = 0; i < k; i++) {
            for (int j = 0; j < n; j++) {
                if (j > 0) arr[j - 1] = arr[j];
            }
            arr[n - 1]++;
        }
        for (int i = 0; i < n; i++) {
            printf("%d ", arr[i]);
        }
        printf("\n");
    }
    return 0;
}

